### 1. Mount tRPC API route: src/app/api/trpc/[trpc]/route.ts
Create a Next.js catch-all API route that delegates to the SDK's tRPC router:
```ts
import { fetchRequestHandler } from '@trpc/server/adapters/fetch';
import { gainforestSdk } from '@/config/gainforest-sdk.server';

const handler = (request: Request) =>
  fetchRequestHandler({
    endpoint: '/api/trpc',
    req: request,
    router: gainforestSdk.appRouter,
    createContext: ({ req }) => gainforestSdk.createContext({ req }),
  });

export { handler as GET, handler as POST };
```

### 2. Create tRPC React provider: src/app/_components/Providers/trpc-provider.tsx
Create a 'use client' component that sets up the tRPC React Query integration:
```ts
'use client';
import { createTRPCReact } from '@trpc/react-query';
import type { AppRouter } from 'gainforest-sdk';
import { customTransformer } from 'gainforest-sdk/utilities/transform';
import type { AllowedPDSDomain } from '@/config/gainforest-sdk';
import { httpBatchLink } from '@trpc/client';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { useState } from 'react';

export const trpcApi = createTRPCReact<AppRouter<AllowedPDSDomain>>();

function getBaseUrl() {
  if (typeof window !== 'undefined') return '';
  if (process.env.VERCEL_URL) return `https://${process.env.VERCEL_URL}`;
  return 'http://localhost:8910';
}

export function TrpcProvider({ children }: { children: React.ReactNode }) {
  // Create separate QueryClient for tRPC (the existing one is for non-tRPC queries)
  const [queryClient] = useState(() => new QueryClient());
  const [trpcClient] = useState(() =>
    trpcApi.createClient({
      links: [
        httpBatchLink({
          url: `${getBaseUrl()}/api/trpc`,
          transformer: customTransformer,
        }),
      ],
    })
  );
  return (
    <trpcApi.Provider client={trpcClient} queryClient={queryClient}>
      <QueryClientProvider client={queryClient}>
        {children}
      </QueryClientProvider>
    </trpcApi.Provider>
  );
}
```

### 3. Add TrpcProvider to the provider tree: src/app/_components/Providers/index.tsx
The current provider tree is: QueryClientProvider > AtprotoProvider > {children}
Wrap the OUTERMOST level with TrpcProvider so it becomes: TrpcProvider > QueryClientProvider > AtprotoProvider > {children}
Import TrpcProvider from './trpc-provider' and wrap the existing tree.

Reference: bumicerts-platform-staging/components/providers/TrpcProvider.tsx

